//! IRP major-function dispatch table for the ext4 FSD boundary.

use wdk_sys::{DRIVER_OBJECT, NTSTATUS, PDEVICE_OBJECT, PDRIVER_OBJECT, PIRP};

use crate::{
    irp::{
        DeviceExecutor, DirectoryControlMinorFunction, DispatchMajor, DispatchTarget,
        IrpCompletion, OwnedIrp, PreparedRequestKind, ReceivedIrp,
    },
    kernel::status::{DriverError, DriverResult},
};

/// WDK major-function callback ABI generated by `wdk-sys`.
type DispatchRoutine = unsafe extern "C" fn(PDEVICE_OBJECT, PIRP) -> NTSTATUS;
/// WDK driver-unload callback ABI generated by `wdk-sys`.
type UnloadRoutine = unsafe extern "C" fn(PDRIVER_OBJECT);

/// Dispatch table installation failed because the WDK table cannot hold a slot.
#[derive(Clone, Copy, Debug)]
pub(crate) struct DispatchInstallError;

/// Typed writer for the WDK major-function dispatch table.
struct DispatchTable<'driver> {
    /// Driver object whose dispatch table is being initialized.
    driver: &'driver mut DRIVER_OBJECT,
}

impl<'driver> DispatchTable<'driver> {
    /// Creates a dispatch-table writer for a driver object.
    fn new(driver: &'driver mut DRIVER_OBJECT) -> Self {
        Self { driver }
    }

    /// Installs the driver unload routine.
    fn unload(&mut self, routine: UnloadRoutine) {
        self.driver.DriverUnload = Some(routine);
    }

    /// Installs one major-function dispatch routine.
    /// # Errors
    ///
    /// Returns an error when `major_function` indexes outside `DRIVER_OBJECT::MajorFunction`.
    fn set(
        &mut self,
        major_function: DispatchMajor,
        routine: DispatchRoutine,
    ) -> Result<(), DispatchInstallError> {
        let Some(slot) = self
            .driver
            .MajorFunction
            .get_mut(major_function.table_index())
        else {
            return Err(DispatchInstallError);
        };

        *slot = Some(routine);
        Ok(())
    }
}

/// Installs the ext4 file-system dispatch table.
/// # Errors
///
/// Returns an error when the WDK dispatch table cannot hold one of ext4win's required IRP major
/// function slots.
pub(crate) fn install(driver: &mut DRIVER_OBJECT) -> Result<(), DispatchInstallError> {
    let mut table = DispatchTable::new(driver);
    table.unload(crate::state::driver_unload);
    table.set(DispatchMajor::Create, create)?;
    table.set(DispatchMajor::Close, close)?;
    table.set(DispatchMajor::Cleanup, cleanup)?;
    table.set(DispatchMajor::Read, read)?;
    table.set(DispatchMajor::FlushBuffers, flush_buffers)?;
    table.set(DispatchMajor::QueryInformation, query_information)?;
    table.set(
        DispatchMajor::QueryVolumeInformation,
        query_volume_information,
    )?;
    table.set(DispatchMajor::DirectoryControl, directory_control)?;
    table.set(DispatchMajor::FileSystemControl, file_system_control)?;
    table.set(DispatchMajor::DeviceControl, device_control)?;
    table.set(DispatchMajor::QueryEa, query_ea)?;
    table.set(DispatchMajor::SetEa, set_ea)?;
    table.set(DispatchMajor::LockControl, lock_control)?;
    table.set(DispatchMajor::Shutdown, shutdown)?;
    table.set(DispatchMajor::QuerySecurity, query_security)?;

    table.set(DispatchMajor::Write, write)?;
    table.set(DispatchMajor::SetInformation, set_information)?;
    table.set(DispatchMajor::SetVolumeInformation, set_volume_information)?;
    table.set(DispatchMajor::SetSecurity, set_security)?;

    Ok(())
}

/// Handles create/open IRPs.
///
/// # Safety
/// The I/O Manager must pass the DEVICE_OBJECT and IRP for the active create/open dispatch call.
unsafe extern "C" fn create(device: PDEVICE_OBJECT, irp: PIRP) -> NTSTATUS {
    dispatch(device, irp, DispatchMajor::Create)
}

